# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(transactions, accounts):
    for transaction in transactions:
        account_id = transaction['account_id']
        amount = transaction['amount']
        
        if account_id in accounts:
            if transaction['type'] == 'deposit':
                accounts[account_id] += amount
            elif transaction['type'] == 'withdrawal':
                if accounts[account_id] >= amount:
                    accounts[account_id] -= amount
                else:
                    raise ValueError("Insufficient funds")
        else:
            raise KeyError("Account not found")

    return accounts

# Example usage:
transactions = [
    {'account_id': 1, 'type': 'deposit', 'amount': 100},
    {'account_id': 2, 'type': 'withdrawal', 'amount': 50}
]

accounts = {1: 0, 2: 100}

updated_accounts = process_transactions(transactions, accounts)
print(updated_accounts)